<template>
  <el-dialog
    :model-value="visible"
    @update:model-value="$emit('update:visible', $event)"
    :title="''"
    width="70%"
    destroy-on-close
  >
    <div class="forum_detail">
      <div class="forum_title">
        <span>{{ recipe.title }}</span>
      </div>
      <div class="forum_info">
        <span class="forum_name"> 发布人：{{ recipe.username }} </span>
        <span class="forum_time">发布时间：{{ recipe.addtime }}</span>
        <span class="forum_calories">热量：{{ recipe.totalCalories }}kcal</span>
        <span
          v-if="recipe.userId == userid && btnAuth('forum', '删除')"
          class="forum_delete"
        >
          <el-button type="danger" size="small" @click="delClick"
            >删除</el-button
          >
        </span>
        <div class="forum_actions">
          <el-button size="small" @click="likeClick">
            <el-icon><Star /></el-icon>
            {{ recipe.likeCount || 0 }}
          </el-button>
          <el-button
            size="small"
            :type="isCollected ? 'primary' : ''"
            @click="collectClick"
          >
            <el-icon><Collection /></el-icon>
            {{ isCollected ? "已收藏" : "收藏" }}
          </el-button>
          <el-button size="small" @click="dislikeClick">
            <el-icon><Close /></el-icon>
            {{ recipe.dislikeCount || 0 }}
          </el-button>
        </div>
      </div>
      <div class="forum_meta">
        <span>健身目标：{{ recipe.fitnessGoal }}</span>
        <span>用餐场景：{{ recipe.mealScene }}</span>
        <span>饮食禁忌：{{ recipe.dietaryRestrictions }}</span>
      </div>
      <el-divider />
      <div class="forum_content">{{ recipe.description }}</div>
      <el-divider />
      <div class="forum_ingredients">
        <h3>食材明细</h3>
        <el-table :data="recipe.ingredients" style="width: 100%">
          <el-table-column
            prop="ingredientName"
            label="食材名称"
          ></el-table-column>
          <el-table-column prop="weight" label="重量"></el-table-column>
          <el-table-column prop="unit" label="单位"></el-table-column>
          <el-table-column prop="calories" label="热量(kcal)"></el-table-column>
        </el-table>
      </div>
    </div>
  </el-dialog>
</template>

<script>
import { ElMessageBox } from "element-plus";
import { Star, Collection, Close } from "@element-plus/icons-vue";

export default {
  name: "RecipeDetailModal",
  components: {
    Star,
    Collection,
    Close,
  },
  props: {
    visible: {
      type: Boolean,
      default: false,
    },
    recipe: {
      type: Object,
      required: true,
    },
    userid: {
      type: Number,
      required: true,
    },
  },
  data() {
    return {
      isCollected: false,
    };
  },
  watch: {
    recipe: {
      handler(newRecipe) {
        if (newRecipe) {
          this.checkCollectionStatus();
        }
      },
      immediate: true,
    },
  },
  emits: ["update:visible", "delete", "collect"],
  methods: {
    checkCollectionStatus() {
      const context = window.$vueApp?.config.globalProperties || this.$root.$;
      if (!context || !this.recipe.id) return;

      // 检查是否已收藏
      context
        ?.$http({
          url: `storeup/isCollect`,
          method: "get",
          params: {
            tablename: "recipe",
            refid: this.recipe.id,
          },
        })
        .then((res) => {
          if (res && res.data && res.data.code === 0) {
            this.isCollected = res.data.data;
          }
        });
    },
    delClick() {
      const context = window.$vueApp?.config.globalProperties;
      if (!context) return;

      ElMessageBox.confirm(`是否删除选中食谱`, "提示", {
        confirmButtonText: "是",
        cancelButtonText: "否",
        type: "warning",
      }).then(() => {
        // 调用删除食谱的API
        context
          ?.$http({
            url: `recipe/delete/${this.recipe.id}`,
            method: "delete",
          })
          .then((res) => {
            // 检查响应数据结构
            if (res && res.data && res.data.code === 0) {
              context?.$toolUtil.message("删除成功", "success", () => {
                this.$emit("delete", this.recipe.id);
                this.$emit("update:visible", false);
              });
            } else {
              console.error("响应数据结构不符合预期:", res);
              context?.$toolUtil.message("删除失败", "error");
            }
          })
          .catch((error) => {
            console.error("请求失败:", error);
            context?.$toolUtil.message("删除失败", "error");
          });
      });
    },
    btnAuth(e, a) {
      const context = window.$vueApp?.config.globalProperties;
      return context?.$toolUtil.isAuth(e, a);
    },
    likeClick() {
      // 尝试从window.$vueApp获取全局属性
      let context = window.$vueApp?.config.globalProperties;

      // 如果window.$vueApp不可用，尝试从this.$root获取
      if (!context) {
        context = this.$root.$;
      }

      if (!context) {
        console.error("无法获取全局上下文");
        return;
      }

      // 检查必要的属性是否存在
      if (!this.recipe || !this.recipe.id) {
        console.error("食谱数据不完整");
        context?.$toolUtil.message("食谱数据不完整", "error");
        return;
      }

      context
        ?.$http({
          url: `recipe/like`,
          method: "post",
          data: {
            id: this.recipe.id,
          },
        })
        .then((res) => {
          if (res && res.data && res.data.code === 0) {
            context?.$toolUtil.message("点赞成功", "success");
            // 更新本地点赞数
            if (this.recipe.likeCount) {
              this.recipe.likeCount++;
            } else {
              this.recipe.likeCount = 1;
            }
          } else {
            console.error("点赞失败，响应数据不符合预期:", res);
            context?.$toolUtil.message("点赞失败", "error");
          }
        })
        .catch((error) => {
          console.error("点赞请求失败:", error);
          context?.$toolUtil.message("点赞失败，请稍后重试", "error");
        });
    },
    collectClick() {
      // 尝试从window.$vueApp获取全局属性
      let context = window.$vueApp?.config.globalProperties;

      // 如果window.$vueApp不可用，尝试从this.$root获取
      if (!context) {
        context = this.$root.$;
      }

      if (!context) {
        console.error("无法获取全局上下文");
        return;
      }

      // 检查必要的属性是否存在
      if (!this.recipe || !this.recipe.id || !this.recipe.title) {
        console.error("食谱数据不完整");
        context?.$toolUtil.message("食谱数据不完整", "error");
        return;
      }

      // 如果已经收藏，则取消收藏
      if (this.isCollected) {
        context
          ?.$http({
            url: `storeup/delete`,
            method: "post",
            data: {
              tablename: "recipe",
              refid: this.recipe.id,
            },
          })
          .then((res) => {
            if (res && res.data && res.data.code === 0) {
              context?.$toolUtil.message("取消收藏成功", "success");
              this.isCollected = false;
              this.$emit("collect", false);
            } else {
              console.error("取消收藏失败，响应数据不符合预期:", res);
              context?.$toolUtil.message("取消收藏失败", "error");
            }
          })
          .catch((error) => {
            console.error("取消收藏请求失败:", error);
            context?.$toolUtil.message("取消收藏失败，请稍后重试", "error");
          });
      } else {
        // 否则添加收藏
        context
          ?.$http({
            url: `storeup/save`,
            method: "post",
            data: {
              tablename: "recipe",
              refid: this.recipe.id,
              name: this.recipe.title,
              picture: this.recipe.picture || "",
            },
          })
          .then((res) => {
            if (res && res.data && res.data.code === 0) {
              context?.$toolUtil.message("收藏成功", "success");
              this.isCollected = true;
              this.$emit("collect", true);
            } else {
              console.error("收藏失败，响应数据不符合预期:", res);
              context?.$toolUtil.message("收藏失败", "error");
            }
          })
          .catch((error) => {
            console.error("收藏请求失败:", error);
            context?.$toolUtil.message("收藏失败，请稍后重试", "error");
          });
      }
    },
    dislikeClick() {
      // 尝试从window.$vueApp获取全局属性
      let context = window.$vueApp?.config.globalProperties;

      // 如果window.$vueApp不可用，尝试从this.$root获取
      if (!context) {
        context = this.$root.$;
      }

      if (!context) {
        console.error("无法获取全局上下文");
        return;
      }

      // 检查必要的属性是否存在
      if (!this.recipe || !this.recipe.id) {
        console.error("食谱数据不完整");
        context?.$toolUtil.message("食谱数据不完整", "error");
        return;
      }

      context
        ?.$http({
          url: `recipe/dislike`,
          method: "post",
          data: {
            id: this.recipe.id,
          },
        })
        .then((res) => {
          if (res && res.data && res.data.code === 0) {
            context?.$toolUtil.message("操作成功", "success");
            // 更新本地踩数
            if (this.recipe.dislikeCount) {
              this.recipe.dislikeCount++;
            } else {
              this.recipe.dislikeCount = 1;
            }
          } else {
            console.error("操作失败，响应数据不符合预期:", res);
            context?.$toolUtil.message("操作失败", "error");
          }
        })
        .catch((error) => {
          console.error("操作请求失败:", error);
          context?.$toolUtil.message("操作失败，请稍后重试", "error");
        });
    },
  },
};
</script>

