<template>
  <div
    class="forum_item"
    @mouseenter="forumEnter"
    @mouseleave="forumLeave"
    @click.stop="handleClick"
  >
    <div class="forum_item_left">
      <span class="forum_item_title">{{ recipe.title }}</span>
      <span class="forum_item_name"> (发布人：{{ recipe.username }}) </span>
      <span class="forum_item_calories">
        (热量：{{ recipe.totalCalories }}kcal)
      </span>
    </div>
    <div
      class="forum_item_btn_box"
      v-if="
        recipe.userId == userid &&
        showButtons &&
        (btnAuth('forum', '修改') || btnAuth('forum', '删除'))
      "
    >
      <el-button
        class="forum_edit_btn"
        v-if="btnAuth('forum', '修改')"
        type="primary"
        @click.stop="editClick"
        >修改</el-button
      >
      <el-button
        class="forum_del_btn"
        v-if="btnAuth('forum', '删除')"
        type="danger"
        @click.stop="delClick"
        >删除</el-button
      >
    </div>
    <div class="forum_time" v-else>{{ recipe.addtime }}</div>
  </div>
</template>

<script>
export default {
  name: "RecipeItem",
  props: {
    recipe: {
      type: Object,
      required: true,
    },
    userid: {
      type: Number,
      required: true,
    },
    showButtons: {
      type: Boolean,
      default: true,
    },
  },
  emits: ["click", "edit", "delete"],
  data() {
    return {
      showButtons: false,
    };
  },
  methods: {
    forumEnter() {
      this.showButtons = true;
    },
    forumLeave() {
      this.showButtons = false;
    },
    handleClick() {
      this.$emit("click", this.recipe);
    },
    editClick() {
      this.$emit("edit", this.recipe);
    },
    delClick() {
      this.$emit("delete", this.recipe);
    },
    btnAuth(e, a) {
      const context = window.$vueApp?.config.globalProperties;
      return context?.$toolUtil.isAuth(e, a);
    },
  },
};
</script>

